      "text": "pam jagaida? kad turreſi tu\nSohdibu pahr manneem Waja-\ntajeein."
    },
    {
      "n": 85,
      "column": "left",
      "text": "Tee Lepnee rohſt man Bed-\nres/ kaſ ne irr pehz tawas Bauf-\nlibas."
    },
    {
      "n": 86,
      "column": "left",
      "text": "Wiſſi tawi Baugſi irr\nPateeſiba/ tee waja mann ar\nMelleem/ palihſs man."
    },
    {
      "n": 87,
      "column": "left",
      "text": "Gann drihs tee mann irr\nisuihzingajcht wirs Semmes/ bet\nes ne eſmu tawas Pawehlefcha-\nnas atſtahjis."
    },
    {
      "n": 88,
      "column": "left",
      "text": "Darri mann dſihwu pehz\ntawas Schehlaſtibas/ tad pa-\nfargaschu es tawas Muttes Lee-\nzibu."
    },
    {
      "n": 89,
      "column": "left",
      "text": "KUNGŚ/ taws Wahrdē\npaſtahw muhſchigi eekſch Deb-\nbeſim."
    },
    {
      "n": 90,
      "column": "left",
      "text": "Tawa Pateeſiba paleek\nſihds Raddu Raddeem/ tu eſſi to\nSemmi ſtiprinajs/ ka ta pa-\nſtahw."
    },
    {
      "n": 91,
      "column": "left",
      "text": "Pehz taween Eſſahkumâen\ntee wehl ſchoddeen ſtahw/ jo wiſ-\nfas Leetas tew kalpo."
    },
    {
      "n": 92,
      "column": "left",
      "text": "Ja tawa Baufſiba ue\nbuhtu manna Gelihgſmoſchana\nbijuti/ es buhtu jaw fenn bohjā\ngahjis eekſch mannahm Beh-\ndahm."
    },
    {
      "n": 93,
      "column": "left",
      "text": "Tawas Pawehlefchanas\nes muhſcham ne aisintriſchu/ jo\nzaur tahm eſſi tu mann dſihwu\ndarrijs."
    },
    {
      "n": 94,
      "column": "left",
      "text": "Es tew peederru/ atpeſti\nmann/ jo es mekleju tawas Pa-\nwehlefchanas."
    },
    {
      "n": 95,
      "column": "right",
      "text": "ni gaida/ ka tee manni nomaita-\nbet es leeſu tawas Leeziba-\nwehra."
    },
    {
      "n": 96,
      "column": "right",
      "text": "Es eſmu wiſſu ſtipru Lee-\ntu Gallu redſejs/ bet taw\nBaufſis itt plachti paſtahtw."
    },
    {
      "n": 97,
      "column": "right",
      "text": "Ka mthleju es taw\nBaufſibu? ta irr manna Pah-\ndohmaſchana ikdeenas."
    },
    {
      "n": 98,
      "column": "right",
      "text": "Tu padarri mann ar ta-\nweem Baufſeem gudraſu/ ne t\nmannus Genaiducekus/ jo ta t\nmuhſchain pee mannis."
    },
    {
      "n": 99,
      "column": "right",
      "text": "Es eſmu wairak ſeina-\nzihts/ ne ka wiſſi manni Ma-\nzitaji/ jo tawas Leezibas i\nmannu Pahrdohmaſchana."
    },
    {
      "n": 100,
      "column": "right",
      "text": "Es eſmu wairak ſaprā-\ntigs/ ne ka tee Wezzajee/ jo t\nturu tawas Pawehlefchanas."
    },
    {
      "n": 101,
      "column": "right",
      "text": "Es atrauju ſawu Ka-\nju no wiſſeem blehdigeem Ze-\nteim/ ka es tawn Wahrdū wa-\nru fargaht."
    },
    {
      "n": 102,
      "column": "right",
      "text": "Es ne atſahpju no t\nwahm Teefahm/ jo tu mal-\nmann."
    },
    {
      "n": 103,
      "column": "right",
      "text": "Zik faldi irr tawi Wah-\ndi mannam Schohdain? itt\nMeddus eekſch mannas Mutte"
    },
    {
      "n": 104,
      "column": "right",
      "text": "Zaur tawahm Paweh-\nſchanahm tohpu es ſaprattig-\ntadeht eenihstu es wiſſus wil-\ngus Zettus."
    },
    {
      "n": 105,
      "column": "right",
      "text": "Tawē Wahrdē irr ma-\nnas Kabjas Spihdekſis/\nweenis Gaiſchums us manne-\nZeſfeem."
    },
    {
      "n": 106,
      "column": "right",
      "text": "Es eſmu ſwichrejs/\ntu"
    }
  ],
  "confidence": "high",
